// NLP-based extraction of scheduling details
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json.queuedRequest || item.json;
  const rawRequest = data.rawRequest || '';

  // Extract meeting title (simple pattern matching)
  let title = 'Meeting';
  const titlePatterns = [
    /(?:meeting|call|discussion|sync)\s+(?:about|regarding|for|on)\s+([\w\s]+)/i,
    /([\w\s]+)\s+(?:meeting|call|discussion)/i
  ];

  for (const pattern of titlePatterns) {
    const match = rawRequest.match(pattern);
    if (match && match[1]) {
      title = match[1].trim();
      break;
    }
  }

  // Extract date/time (basic patterns)
  let dateTime = null;
  let duration = 30; // default 30 minutes

  const timePatterns = [
    /tomorrow\s+at\s+(\d{1,2}):?(\d{2})?\s*(am|pm)?/i,
    /(?:on\s+)?(\d{1,2})\/(\d{1,2})\s+at\s+(\d{1,2}):?(\d{2})?\s*(am|pm)?/i,
    /(monday|tuesday|wednesday|thursday|friday|saturday|sunday)\s+at\s+(\d{1,2}):?(\d{2})?\s*(am|pm)?/i
  ];

  // Duration extraction
  const durationMatch = rawRequest.match(/(\d+)\s*(hour|hr|minute|min)s?/i);
  if (durationMatch) {
    const value = parseInt(durationMatch[1]);
    const unit = durationMatch[2].toLowerCase();
    duration = unit.startsWith('hour') || unit === 'hr' ? value * 60 : value;
  }

  // Parse "tomorrow at 2pm" example
  const tomorrowMatch = rawRequest.match(/tomorrow\s+at\s+(\d{1,2}):?(\d{2})?\s*(am|pm)?/i);
  if (tomorrowMatch) {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    let hours = parseInt(tomorrowMatch[1]);
    const minutes = tomorrowMatch[2] ? parseInt(tomorrowMatch[2]) : 0;
    const meridiem = tomorrowMatch[3]?.toLowerCase();

    if (meridiem === 'pm' && hours < 12) hours += 12;
    if (meridiem === 'am' && hours === 12) hours = 0;

    tomorrow.setHours(hours, minutes, 0, 0);
    dateTime = tomorrow.toISOString();
  }

  // Extract attendees (email pattern)
  const emailPattern = /[\w.-]+@[\w.-]+\.[\w]+/g;
  const attendees = rawRequest.match(emailPattern) || [];

  // Add requestor if not in attendees
  if (data.requestorEmail && !attendees.includes(data.requestorEmail)) {
    attendees.unshift(data.requestorEmail);
  }

  // Extract location
  let location = 'virtual';
  const locationPatterns = [
    /(?:at|in|location:?)\s+([\w\s]+(?:room|office|building|floor))/i,
    /zoom|teams|meet|webex/i
  ];

  for (const pattern of locationPatterns) {
    const match = rawRequest.match(pattern);
    if (match) {
      location = match[0];
      break;
    }
  }

  const extracted = {
    ...data,
    extracted: {
      title: title,
      dateTime: dateTime,
      duration: duration,
      attendees: attendees,
      location: location,
      description: rawRequest,
      extractionConfidence: dateTime ? 0.8 : 0.3
    },
    stage: 'extracted',
    processedAt: new Date().toISOString()
  };

  results.push({ json: extracted });
}

return results;

// Normalize and standardize extracted data
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const extracted = data.extracted;

  // Normalize date/time to ISO 8601 format
  let normalizedDateTime = extracted.dateTime;
  if (!normalizedDateTime) {
    // If no date extracted, suggest next available slot (tomorrow 2pm)
    const defaultDate = new Date();
    defaultDate.setDate(defaultDate.getDate() + 1);
    defaultDate.setHours(14, 0, 0, 0);
    normalizedDateTime = defaultDate.toISOString();
  }

  // Normalize duration (ensure it's a valid number)
  let normalizedDuration = extracted.duration;
  if (!normalizedDuration || normalizedDuration < 15) {
    normalizedDuration = 30; // Default to 30 minutes
  }
  if (normalizedDuration > 480) {
    normalizedDuration = 480; // Max 8 hours
  }

  // Normalize attendees (validate emails)
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const normalizedAttendees = extracted.attendees.filter(email => 
    emailRegex.test(email)
  );

  // Normalize location
  let normalizedLocation = extracted.location;
  if (normalizedLocation.toLowerCase().match(/zoom|teams|meet|webex/)) {
    normalizedLocation = 'Virtual Meeting';
  }

  // Calculate end time
  const startTime = new Date(normalizedDateTime);
  const endTime = new Date(startTime.getTime() + normalizedDuration * 60000);

  const normalized = {
    ...data,
    normalized: {
      title: extracted.title,
      startTime: startTime.toISOString(),
      endTime: endTime.toISOString(),
      duration: normalizedDuration,
      attendees: normalizedAttendees,
      location: normalizedLocation,
      description: extracted.description,
      timezone: process.env.CALENDAR_TIMEZONE || 'America/New_York',
      allDay: false,
      reminders: [
        { method: 'email', minutes: 30 },
        { method: 'popup', minutes: 10 }
      ]
    },
    stage: 'normalized',
    processedAt: new Date().toISOString()
  };

  results.push({ json: normalized });
}

return results;
